import Card from '@mui/material/Card';
import { User } from '../../../../models/user/userModel';
import UsersTable from './UsersTable';

function Users() {
    const users: User[] = [
        {
            _id:'1',
            name:'Andy',
            email:'andy@email.com',
            stars:'4',
            status: 'formal'
        },
        {
            _id:'2',
            name:'Max',
            email:'max@email.com',
            stars:'4',
            status: 'formal'
        },
        {
            _id:'1',
            name:'pedro',
            email:'pedro@email.com',
            stars:'3',
            status: 'deptor'
        }
        
    ];

    return (
        <Card>
            <UsersTable users={users} />
        </Card>
    );
}

export default Users;
